import{_ as i,c as t,o as a,aj as n}from"./chunks/framework.CynFBi0q.js";const k=JSON.parse('{"title":"第1章 AI 编程范式与 Vibe Coding 导论","description":"","frontmatter":{},"headers":[],"relativePath":"handbook/ai-sdd/chapter_1.md","filePath":"handbook/ai-sdd/chapter_1.md","lastUpdated":1781883904000}'),e={name:"handbook/ai-sdd/chapter_1.md"};function p(d,s,l,r,h,o){return a(),t("div",null,[...s[0]||(s[0]=[n(`<h1 id="第1章-ai-编程范式与-vibe-coding-导论" tabindex="-1">第1章 AI 编程范式与 Vibe Coding 导论 <a class="header-anchor" href="#第1章-ai-编程范式与-vibe-coding-导论" aria-label="Permalink to “第1章 AI 编程范式与 Vibe Coding 导论”">​</a></h1><p>软件开发的世界正在经历一场静悄悄的革命。过去几十年里，我们习惯了从需求文档到代码实现的漫长路径，习惯了在 IDE 中逐行敲击键盘，习惯了 Stack Overflow 上反复搜索答案。但当 AI 真正理解了你的意图并直接生成可用代码时，一切都变了。这一章，我们从宏观视角审视这场变革，理解 Vibe Coding 到底意味着什么，它从何而来，又将走向何方。</p><hr><h2 id="_1-1-软件开发范式的三代演进" tabindex="-1">1.1 软件开发范式的三代演进 <a class="header-anchor" href="#_1-1-软件开发范式的三代演进" aria-label="Permalink to “1.1 软件开发范式的三代演进”">​</a></h2><p>回顾软件开发的历史，我们可以清晰地划分出三代编程范式。每一代的更替，本质上都是人机交互方式的根本性变革。</p><p><strong>第一代：手工编码范式（1950s-2000s）</strong></p><p>这是最原始也最持久的范式。程序员通过键盘将逻辑逐行写入源文件，编译器或解释器负责将代码转化为机器可执行的指令。这个阶段的核心特征是&quot;人写代码，机器执行&quot;。开发效率完全取决于程序员的经验、记忆力和打字速度。</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 典型的第一代开发流程</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vim</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main.c</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # 手写代码</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gcc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main.c</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 编译</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./app</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">             # 运行</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>这一阶段的效率瓶颈显而易见：人类大脑的短期记忆容量有限，API 文档查阅占据了大量时间，而重复性的样板代码（boilerplate）消耗了本该用于核心逻辑的精力。</p><p><strong>第二代：辅助编码范式（2010s-2023）</strong></p><p>以 GitHub Copilot 的发布为标志，AI 开始介入编码过程。这一代范式的核心特征是&quot;人机协作&quot;：AI 根据上下文补全代码片段，生成函数实现，但决策权仍然牢牢掌握在人类手中。IntelliSense、代码片段（snippets）、自动补全等特性是这一阶段的典型产物。</p><div class="language-python line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Copilot 风格的辅助编码</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">def</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> calculate_total</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(items):</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 输入函数签名后，AI 自动补全函数体</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    return</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> sum</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(item[</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;price&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> item[</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;quantity&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">for</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> item </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">in</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> items)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>辅助编码范式的进步是显著的，但它有明确的边界：AI 只能&quot;续写&quot;，不能&quot;创造&quot;。程序员仍然需要自己拆解问题、设计架构、规划模块，AI 的角色更像一个高效的打字员。</p><p><strong>第三代：意图驱动范式（2024-至今）</strong></p><p>Vibe Coding 代表了第三代范式的到来。在这个阶段，程序员不再逐行编写代码，而是通过自然语言描述意图，AI 负责理解需求、拆解任务、生成代码并验证结果。核心转变是：从&quot;告诉计算机怎么做&quot;到&quot;告诉计算机做什么&quot;。</p><table tabindex="0"><thead><tr><th>维度</th><th>第一代：手工编码</th><th>第二代：辅助编码</th><th>第三代：意图驱动</th></tr></thead><tbody><tr><td>人机关系</td><td>人写机器执行</td><td>人机协作</td><td>人意图机器实现</td></tr><tr><td>交互方式</td><td>键盘输入代码</td><td>补全+Tab接受</td><td>自然语言描述</td></tr><tr><td>核心技能</td><td>语法记忆+算法</td><td>Prompt技巧+审查</td><td>架构思维+验证</td></tr><tr><td>效率瓶颈</td><td>人的编码速度</td><td>人的审查速度</td><td>人的意图表达精度</td></tr><tr><td>错误来源</td><td>逻辑错误</td><td>补全偏差</td><td>意图偏差</td></tr></tbody></table><p>这三代范式并非完全替代关系，而是层层叠加的。即使在 Vibe Coding 时代，程序员仍然需要阅读和审查代码，甚至偶尔手写关键逻辑。但主战场已经转移。</p><hr><h2 id="_1-2-什么是-vibe-coding-——概念、起源与行业争议" tabindex="-1">1.2 什么是 Vibe Coding？——概念、起源与行业争议 <a class="header-anchor" href="#_1-2-什么是-vibe-coding-——概念、起源与行业争议" aria-label="Permalink to “1.2 什么是 Vibe Coding？——概念、起源与行业争议”">​</a></h2><p><strong>Vibe Coding 的定义</strong></p><p>Vibe Coding 一词由 Andrej Karpathy 在 2025 年初首次提出，他将其描述为一种&quot;完全靠感觉编程&quot;的方式——你不需要理解每一行代码的细节，只需要对 AI 说出你想要什么，然后接受它给出的结果。这个概念迅速在技术社区引爆讨论。</p><p>更严谨地说，Vibe Coding 是一种以自然语言意图表达为核心、以 AI 代码生成为引擎、以人类审查和验证为保障的软件开发方式。它不要求开发者逐行编写代码，而是要求开发者精确地描述需求、高效地审查输出、系统地验证结果。</p><p><strong>起源与演变</strong></p><p>Vibe Coding 并非凭空出现，它是多个技术趋势交汇的产物：</p><ul><li>大语言模型能力的飞跃：GPT-4、Claude 3.5 Sonnet 等模型在代码生成质量上的突破</li><li>AI 编程工具的成熟：Cursor、Codex、Claude Code 等工具提供了流畅的交互体验</li><li>规范驱动开发（SDD）理念的兴起：为 AI 生成代码提供了结构化的约束框架</li></ul><p>Karpathy 的原始表述带有一种&quot;放手让 AI 去做&quot;的潇洒感，但社区很快发现，完全不加约束的 Vibe Coding 在复杂项目中会迅速失控。于是，从&quot;纯粹的感觉编程&quot;到&quot;意图驱动+规范约束&quot;的务实版本，Vibe Coding 的内涵在不断进化。</p><p><strong>行业争议</strong></p><p>围绕 Vibe Coding 的争议从未停止，主要集中在三个层面：</p><ol><li><strong>质量控制问题</strong>：AI 生成的代码是否可靠？谁来为 bug 负责？</li><li><strong>开发者能力退化</strong>：长期依赖 AI 生成代码，程序员的底层能力是否会萎缩？</li><li><strong>适用边界模糊</strong>：Vibe Coding 适合什么场景？企业级项目能否用？</li></ol><p>这些争议的核心矛盾在于：Vibe Coding 大幅降低了&quot;写出代码&quot;的门槛，但&quot;写出好代码&quot;的门槛并未降低，反而要求开发者具备更强的架构思维和验证能力。这正是 Harness Engineering 和 SDD 要解决的核心问题。</p><hr><h2 id="_1-3-vibe-coding-的核心特征-意图驱动与上下文感知" tabindex="-1">1.3 Vibe Coding 的核心特征：意图驱动与上下文感知 <a class="header-anchor" href="#_1-3-vibe-coding-的核心特征-意图驱动与上下文感知" aria-label="Permalink to “1.3 Vibe Coding 的核心特征：意图驱动与上下文感知”">​</a></h2><p>理解 Vibe Coding 的本质，需要抓住两个核心特征。</p><p><strong>意图驱动（Intent-Driven）</strong></p><p>传统编程中，开发者需要将高层意图翻译成低层代码。比如&quot;我想做一个用户登录功能&quot;，你需要手动实现路由定义、参数校验、数据库查询、Token 生成等一系列细节。而在 Vibe Coding 模式下，你只需要表达意图：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>实现一个用户登录接口，支持邮箱和手机号登录，</span></span>
<span class="line"><span>返回 JWT Token，有效期 24 小时</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>AI 会根据这段描述生成完整的实现代码。开发者的精力从&quot;如何实现&quot;转向&quot;要实现什么&quot;和&quot;实现是否正确&quot;。</p><p>但意图驱动也带来了新的挑战：意图的表达精度直接决定了代码质量。模糊的需求描述会产生模糊的代码实现。这也是为什么 Prompt 工程在 Vibe Coding 中如此重要——我们在第11章会深入探讨。</p><p><strong>上下文感知（Context-Aware）</strong></p><p>Vibe Coding 不是简单的&quot;自然语言转代码&quot;。AI 编程工具会实时感知项目的上下文信息：</p><ul><li>已有的代码结构和命名约定</li><li>项目使用的技术栈和依赖版本</li><li>数据库 Schema 和 API 接口定义</li><li>团队的编码规范和架构模式</li></ul><div class="language-javascript line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 当项目中已有 User 模型时，AI 生成的代码会自动对齐</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 而不是凭空创造一个新的模型定义</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">async</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> function</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> getUserById</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">id</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> string</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Promise</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">User</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt; {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  return</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> await</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> this</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.userRepository.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">findById</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(id);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>上下文感知能力是 AI 编程工具区别于早期代码生成工具的关键。它让 AI 生成的代码不再是孤立的代码片段，而是融入项目整体架构的有机组成部分。</p><p>但这种感知能力有其边界。当项目规模增大、上下文窗口溢出时，AI 会&quot;遗忘&quot;关键信息，导致生成的代码与项目风格不一致。这恰恰是 Harness Engineering 中上下文管理（Context Management）要解决的核心问题。</p><hr><h2 id="_1-4-vibe-coding-的难点与常见陷阱" tabindex="-1">1.4 Vibe Coding 的难点与常见陷阱 <a class="header-anchor" href="#_1-4-vibe-coding-的难点与常见陷阱" aria-label="Permalink to “1.4 Vibe Coding 的难点与常见陷阱”">​</a></h2><p>Vibe Coding 看起来简单——说几句话就能生成代码，但实际上存在大量隐性难点，初学者很容易踩坑。</p><p><strong>难点一：意图表达的精确性</strong></p><p>人类习惯用模糊的自然语言交流，但 AI 对模糊指令的解读可能完全偏离你的预期。</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>// 模糊指令</span></span>
<span class="line"><span>&quot;做一个搜索功能&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// 精确指令</span></span>
<span class="line"><span>&quot;实现一个商品搜索接口，支持按名称模糊查询和价格区间筛选，</span></span>
<span class="line"><span>返回分页结果，每页 20 条，按相关度排序&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>精确的意图表达需要开发者对需求有深度的理解，这恰恰是最难的部分。</p><p><strong>难点二：上下文窗口的有限性</strong></p><p>当前主流 AI 模型的上下文窗口在 128K-200K Token 之间。对于一个中大型项目，上下文很快就会被填满。当 AI 无法&quot;看到&quot;项目的全貌时，生成的代码质量会急剧下降。</p><p><strong>难点三：幻觉与错误代码</strong></p><p>AI 会自信地生成看似正确但实际有 bug 的代码，包括：</p><ul><li>调用不存在的 API 或方法</li><li>使用过时的库版本</li><li>逻辑正确但性能极差的实现</li><li>忽略边界条件和异常处理</li></ul><p><strong>难点四：缺乏全局架构视角</strong></p><p>AI 擅长生成局部代码，但不擅长进行全局架构决策。让 AI 设计一个微服务架构，它可能给出看似合理的方案，但忽略了团队的运维能力、流量规模、数据一致性等实际约束。</p><p><strong>常见陷阱汇总</strong></p><table tabindex="0"><thead><tr><th>陷阱</th><th>表现</th><th>根因</th><th>应对策略</th></tr></thead><tbody><tr><td>意图漂移</td><td>AI 生成的代码偏离需求</td><td>指令模糊或上下文丢失</td><td>精确 Prompt + SDD 规范</td></tr><tr><td>幻觉代码</td><td>调用不存在的 API</td><td>模型训练数据局限</td><td>代码审查 + 验证闭环</td></tr><tr><td>上下文溢出</td><td>代码风格不一致</td><td>上下文窗口有限</td><td>Harness 上下文管理</td></tr><tr><td>架构失控</td><td>模块间耦合严重</td><td>缺乏全局规划</td><td>Spec 驱动 + 架构评审</td></tr><tr><td>过度依赖</td><td>离开 AI 就无法开发</td><td>技能退化</td><td>定期手写核心逻辑</td></tr></tbody></table><hr><h2 id="_1-5-vibe-coding-的开发生命周期模型" tabindex="-1">1.5 Vibe Coding 的开发生命周期模型 <a class="header-anchor" href="#_1-5-vibe-coding-的开发生命周期模型" aria-label="Permalink to “1.5 Vibe Coding 的开发生命周期模型”">​</a></h2><p>传统软件开发生命周期（SDLC）包含需求、设计、开发、测试、部署等阶段。Vibe Coding 没有改变这些阶段的本质，但彻底改变了每个阶段的执行方式。</p><p><strong>Vibe Coding 生命周期（VC-SDLC）</strong></p><p><strong>阶段一：意图表达（Intent Expression）</strong></p><p>替代传统的需求文档编写。开发者用自然语言描述需求，AI 辅助将模糊想法转化为结构化的 Spec 文档。SDD 规范在这一阶段发挥核心作用。</p><p><strong>阶段二：规范驱动（Spec-Driven Design）</strong></p><p>将意图转化为可执行的开发规范，包括架构设计、接口定义、数据模型等。Harness Engineering 的 Feature List 和任务拆解能力在此阶段发挥作用。</p><p><strong>阶段三：AI 生成（AI Generation）</strong></p><p>AI 根据 Spec 和上下文生成代码。这不是简单的代码补全，而是完整的模块实现。开发者在此阶段的核心工作是审查和微调，而非编写。</p><p><strong>阶段四：验证闭环（Verification Loop）</strong></p><p>对 AI 生成的代码进行系统验证，包括自动化测试、代码审查、性能检测等。Harness Engineering 的 Verification Loop 机制确保每次生成都经过充分验证。</p><p><strong>阶段五：迭代优化（Iteration &amp; Optimization）</strong></p><p>根据验证结果进行迭代，AI 辅助修复 bug、优化性能、重构代码。SDD 迭代规范确保每次变更都有迹可循。</p><p><strong>阶段六：部署交付（Deployment &amp; Delivery）</strong></p><p>AI 辅助完成部署方案设计、环境配置、上线验证等工作。整个生命周期形成闭环。</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>意图表达 → 规范驱动 → AI 生成 → 验证闭环 → 迭代优化 → 部署交付</span></span>
<span class="line"><span>    ↑                                                    |</span></span>
<span class="line"><span>    └────────────────────────────────────────────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p><strong>与传统 SDLC 的对比</strong></p><table tabindex="0"><thead><tr><th>阶段</th><th>传统 SDLC</th><th>Vibe Coding SDLC</th></tr></thead><tbody><tr><td>需求</td><td>文档驱动，人工编写</td><td>意图驱动，AI 辅助生成 Spec</td></tr><tr><td>设计</td><td>架构师主导，文档先行</td><td>Spec 驱动，AI 辅助架构决策</td></tr><tr><td>开发</td><td>人工编码为主</td><td>AI 生成+人工审查</td></tr><tr><td>测试</td><td>测试团队执行</td><td>AI 自动化测试+验证闭环</td></tr><tr><td>部署</td><td>运维团队执行</td><td>AI 辅助部署+自动验收</td></tr><tr><td>迭代</td><td>周期较长</td><td>持续迭代，快速反馈</td></tr></tbody></table><p>Vibe Coding 生命周期的核心变化在于：人从&quot;执行者&quot;变为&quot;指挥者&quot;和&quot;审查者&quot;。但这并不意味着人的角色被弱化——恰恰相反，对人的架构思维、验证能力和规范意识提出了更高的要求。</p><p>这正是后续章节要深入探讨的：Harness Engineering 提供了驾驭 AI 的工程框架，SDD 提供了规范驱动的开发方法论，两者结合才能让 Vibe Coding 从&quot;感觉编程&quot;进化为&quot;可靠的工程实践&quot;。</p><hr><p><strong>本章小结</strong></p><table tabindex="0"><thead><tr><th>概念</th><th>核心要点</th></tr></thead><tbody><tr><td>三代范式</td><td>手工编码 → 辅助编码 → 意图驱动，每代都是人机交互方式的根本变革</td></tr><tr><td>Vibe Coding</td><td>以自然语言意图表达为核心，AI 代码生成为引擎，人类审查验证为保障</td></tr><tr><td>核心特征</td><td>意图驱动（精确表达需求）+ 上下文感知（融入项目全局）</td></tr><tr><td>难点与陷阱</td><td>意图漂移、幻觉代码、上下文溢出、架构失控、过度依赖</td></tr><tr><td>生命周期</td><td>意图表达 → 规范驱动 → AI 生成 → 验证闭环 → 迭代优化 → 部署交付</td></tr></tbody></table><p>下一章，我们将全面盘点 AI 全栈开发的工具链生态，横向对比 Codex、Claude Code 等主流工具，帮你建立精准的工具选型能力。</p>`,85)])])}const b=i(e,[["render",p]]);export{k as __pageData,b as default};
